1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	
10	const BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
20	type Customer = { yearsWithMHPCO: number };
21	type Step = { op: "quote"; items: Item[] };
22	type Scenario = { customer: Customer; steps: Step[] };
23	
24	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const BLOCK_SIZE = 3;
28	const BLOCK_BASE_PREMIUM = 60;
29	
30	const sumBasePremiums = (items: Item[]): number =>
31	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
32	
33	const componentGroupSubtotalOf = (group: Item[]): number =>
34	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
35	
36	const groupByType = (items: Item[]): Map<string, Item[]> => {
37	  const groups = new Map<string, Item[]>();
38	  for (const item of items) {
39	    const existing = groups.get(item.type) ?? [];
40	    existing.push(item);
41	    groups.set(item.type, existing);
42	  }
43	  return groups;
44	};
45	
46	const componentSubtotalOf = (components: Item[]): number =>
47	  [...groupByType(components).values()].reduce(
48	    (sum, group) => sum + componentGroupSubtotalOf(group),
49	    0,
50	  );
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
53	
54	const policyBaseOf = (items: Item[]): number => {
55	  const components = items.filter(isComponent);
56	  const standaloneItems = items.filter((item) => !isComponent(item));
57	  return sumBasePremiums(standaloneItems) + componentSubtotalOf(components);
58	};
59	
60	const firstInsuranceSurchargeOf = (policyBase: number): number =>
61	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
62	
63	const cursedSurchargeOf = (item: Item): number =>
64	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
65	
66	const highEnchantmentSurchargeOf = (item: Item): number =>
67	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
68	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
69	    : 0;
70	
71	const itemSurchargeOf = (item: Item): number =>
72	  cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item);
73	
74	const itemSurchargesOf = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemSurchargeOf(item), 0);
76	
77	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
78	
79	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
80	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
81	
82	const followUpDiscountOf = (policyBase: number, isFollowUp: boolean): number =>
83	  isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
84	
85	const policySurchargesOf = (policyBase: number): number =>
86	  firstInsuranceSurchargeOf(policyBase);
87	
88	const policyDiscountsOf = (
89	  policyBase: number,
90	  customer: Customer,
91	  isFollowUp: boolean,
92	): number =>
93	  loyaltyDiscountOf(policyBase, customer) + followUpDiscountOf(policyBase, isFollowUp);
94	
95	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
96	  const policyBase = policyBaseOf(items);
97	  const rawPremium =
98	    policyBase +
99	    itemSurchargesOf(items) +
100	    policySurchargesOf(policyBase) -
101	    policyDiscountsOf(policyBase, customer, isFollowUp) +
102	    PROCESSING_FEE;
103	  return roundUpInMHPCOFavor(rawPremium);
104	};
105	
106	const isFollowUpContract = (stepIndex: number): boolean => stepIndex > 0;
107	
108	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
109	  const results = scenario.steps.map((step, index) => ({
110	    premium: quotePremium(step.items, scenario.customer, isFollowUpContract(index)),
111	  }));
112	  return { results };
113	};
